"""solution.py - TeamCollaborationManager: a team/project/task collaboration system."""

import csv
import io
import json
import threading
from dataclasses import dataclass, replace
from datetime import datetime
from enum import Enum
from typing import Optional


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------

class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------

class TeamCollaborationError(Exception):
    pass

class ValidationError(TeamCollaborationError):
    pass

class NotFoundError(TeamCollaborationError):
    pass

class AuthorizationError(TeamCollaborationError):
    pass

class DuplicateError(TeamCollaborationError):
    pass

class ConflictError(TeamCollaborationError):
    pass


# ---------------------------------------------------------------------------
# Dataclasses
# ---------------------------------------------------------------------------

@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    project_id: int
    created_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: list
    created_at: datetime
    edited_at: Optional[datetime]


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Clone helpers (lightweight alternatives to copy.deepcopy)
# ---------------------------------------------------------------------------

def _clone_msg(msg):
    """Return an isolated Message copy with a fresh attachments list and fresh Attachment objects."""
    return replace(msg, attachments=[replace(a) for a in msg.attachments])


# ---------------------------------------------------------------------------
# Sub-stores (each holds a reference to the shared manager lock)
# ---------------------------------------------------------------------------

class _Store:
    def __init__(self, lock):
        self._lock = lock


class UserStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self._users = {}        # id -> User
        self._by_username = {}  # username -> id
        self._by_email = {}     # email -> id


class ProjectStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self._projects = {}     # id -> Project


class TaskStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self._tasks = {}        # id -> Task
        self._by_project = {}   # project_id -> set[task_id]
        self._by_assignee = {}  # assignee_id -> set[task_id]


class MessageStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self._messages = {}     # id -> Message
        self._by_project = {}   # project_id -> list[msg_id]
        self._by_task = {}      # task_id -> list[msg_id]


class PerformanceStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self._ratings = {}              # id -> Rating
        self._ratings_by_ratee = {}     # ratee_id -> list[rating_id]


class ReportStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------

class TeamCollaborationManager:
    def __init__(self, now=None):
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        self.users = UserStore(self._lock)
        self.projects = ProjectStore(self._lock)
        self.tasks = TaskStore(self._lock)
        self.messages = MessageStore(self._lock)
        self.performance = PerformanceStore(self._lock)
        self.reports = ReportStore(self._lock)

    # -- Private helpers -----------------------------------------------------

    def _next_id(self):
        """Increment and return the global monotonic ID counter (call under lock)."""
        self._id_counter += 1
        return self._id_counter

    def _now_dt(self):
        return self._now()

    # -----------------------------------------------------------------------
    # Users
    # -----------------------------------------------------------------------

    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            username = username.strip() if username else ""
            if not username:
                raise ValidationError("Username must not be empty")
            if not email or "@" not in email:
                raise ValidationError("Email must contain '@'")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole instance")
            if username in self.users._by_username:
                raise DuplicateError("Username already exists")
            if email in self.users._by_email:
                raise DuplicateError("Email already exists")

            uid = self._next_id()
            user = User(id=uid, username=username, email=email,
                        role=role, created_at=self._now_dt())
            self.users._users[uid] = user
            self.users._by_username[username] = uid
            self.users._by_email[email] = uid
            return replace(user)

    def get_user(self, user_id):
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            return replace(self.users._users[user_id])

    def list_users(self):
        with self._lock:
            return [
                replace(u)
                for u in sorted(self.users._users.values(), key=lambda x: x.id)
            ]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            user = self.users._users[user_id]

            if username is not None:
                existing = self.users._by_username.get(username)
                if existing is not None and existing != user_id:
                    raise DuplicateError("Username already exists")
            if email is not None:
                if "@" not in email:
                    raise ValidationError("Email must contain '@'")
                existing = self.users._by_email.get(email)
                if existing is not None and existing != user_id:
                    raise DuplicateError("Email already exists")

            if username is not None:
                del self.users._by_username[user.username]
                user.username = username
                self.users._by_username[username] = user_id
            if email is not None:
                del self.users._by_email[user.email]
                user.email = email
                self.users._by_email[email] = user_id
            if role is not None:
                user.role = role

            return replace(user)

    def delete_user(self, user_id):
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            for project in self.projects._projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("User owns a project")
            for task_id in self.tasks._by_assignee.get(user_id, set()):
                task = self.tasks._tasks.get(task_id)
                if task and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("User has non-completed tasks")

            user = self.users._users.pop(user_id)
            del self.users._by_username[user.username]
            del self.users._by_email[user.email]

    # -----------------------------------------------------------------------
    # Projects
    # -----------------------------------------------------------------------

    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if owner_id not in self.users._users:
                raise NotFoundError("Owner not found")
            if not name or not name.strip():
                raise ValidationError("Project name must not be empty")
            if end_date < start_date:
                raise ValidationError("end_date must be >= start_date")

            pid = self._next_id()
            project = Project(id=pid, name=name, description=description,
                              start_date=start_date, end_date=end_date,
                              owner_id=owner_id)
            self.projects._projects[pid] = project
            return replace(project)

    def get_project(self, project_id):
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            return replace(self.projects._projects[project_id])

    def list_projects(self):
        with self._lock:
            return [
                replace(p)
                for p in sorted(self.projects._projects.values(), key=lambda x: x.id)
            ]

    def update_project(self, project_id, name=None, description=None,
                       start_date=None, end_date=None):
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            project = self.projects._projects[project_id]
            if name is not None and not name.strip():
                raise ValidationError("Project name must not be empty")

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date must be >= start_date")

            if name is not None:
                project.name = name
            if description is not None:
                project.description = description
            project.start_date = new_start
            project.end_date = new_end
            return replace(project)

    def delete_project(self, project_id):
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")

            # Cascade: remove all tasks in this project
            for task_id in list(self.tasks._by_project.get(project_id, set())):
                task = self.tasks._tasks.pop(task_id, None)
                if task and task.assignee_id is not None:
                    self.tasks._by_assignee.get(task.assignee_id, set()).discard(task_id)
            self.tasks._by_project.pop(project_id, None)

            # Cascade: remove all project-scoped messages
            for msg_id in list(self.messages._by_project.get(project_id, [])):
                self.messages._messages.pop(msg_id, None)
            self.messages._by_project.pop(project_id, None)

            del self.projects._projects[project_id]

    # -----------------------------------------------------------------------
    # Tasks
    # -----------------------------------------------------------------------

    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            if assignee_id is not None and assignee_id not in self.users._users:
                raise NotFoundError("Assignee not found")
            if not title or not title.strip():
                raise ValidationError("Task title must not be empty")
            project = self.projects._projects[project_id]
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("Deadline is before project start_date")

            tid = self._next_id()
            task = Task(id=tid, title=title, status=TaskStatus.NOT_STARTED,
                        assignee_id=assignee_id, deadline=deadline,
                        started_at=None, completed_at=None,
                        project_id=project_id, created_at=self._now_dt())
            self.tasks._tasks[tid] = task
            self.tasks._by_project.setdefault(project_id, set()).add(tid)
            if assignee_id is not None:
                self.tasks._by_assignee.setdefault(assignee_id, set()).add(tid)
            return replace(task)

    def get_task(self, task_id):
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            return replace(self.tasks._tasks[task_id])

    def list_tasks_by_project(self, project_id):
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            ids = sorted(self.tasks._by_project.get(project_id, set()))
            tasks_dict = self.tasks._tasks
            return [replace(tasks_dict[i]) for i in ids if i in tasks_dict]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            if assignee_id not in self.users._users:
                raise NotFoundError("User not found")
            ids = sorted(self.tasks._by_assignee.get(assignee_id, set()))
            tasks_dict = self.tasks._tasks
            return [replace(tasks_dict[i]) for i in ids if i in tasks_dict]

    def _do_assign(self, task_id, assignee_id):
        """Update task assignee and both index directions (must be called under lock)."""
        task = self.tasks._tasks[task_id]
        old = task.assignee_id
        if old is not None:
            self.tasks._by_assignee.get(old, set()).discard(task_id)
        task.assignee_id = assignee_id
        self.tasks._by_assignee.setdefault(assignee_id, set()).add(task_id)
        return task

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            if assignee_id not in self.users._users:
                raise NotFoundError("Assignee not found")
            return replace(self._do_assign(task_id, assignee_id))

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            if new_assignee_id not in self.users._users:
                raise NotFoundError("New assignee not found")
            return replace(self._do_assign(task_id, new_assignee_id))

    def unassign_task(self, task_id):
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            task = self.tasks._tasks[task_id]
            if task.assignee_id is not None:
                self.tasks._by_assignee.get(task.assignee_id, set()).discard(task_id)
            task.assignee_id = None
            return replace(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            task = self.tasks._tasks[task_id]
            if deadline is not None:
                project = self.projects._projects[task.project_id]
                if deadline < project.start_date:
                    raise ValidationError("Deadline is before project start_date")
            task.deadline = deadline
            return replace(task)

    def update_status(self, task_id, status):
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus instance")
            task = self.tasks._tasks[task_id]
            now = self._now_dt()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return replace(task)

    # -----------------------------------------------------------------------
    # Messaging
    # -----------------------------------------------------------------------

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        with self._lock:
            # Exactly one target must be specified (check before any existence lookup)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "Exactly one of project_id or task_id must be provided")
            if author_id not in self.users._users:
                raise NotFoundError("Author not found")
            if project_id is not None and project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            if task_id is not None and task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            if parent_id is not None and parent_id not in self.messages._messages:
                raise NotFoundError("Parent message not found")
            if not body and not attachments:
                raise ValidationError("Body and attachments cannot both be empty")

            now = self._now_dt()
            att_list = []
            if attachments:
                for fname, data in attachments:
                    att_list.append(Attachment(filename=fname, size=len(data),
                                               uploaded_by=author_id,
                                               uploaded_at=now))

            mid = self._next_id()
            msg = Message(id=mid, author_id=author_id, body=body,
                          project_id=project_id, task_id=task_id,
                          parent_id=parent_id, attachments=att_list,
                          created_at=now, edited_at=None)
            self.messages._messages[mid] = msg
            if project_id is not None:
                self.messages._by_project.setdefault(project_id, []).append(mid)
            if task_id is not None:
                self.messages._by_task.setdefault(task_id, []).append(mid)
            return _clone_msg(msg)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            if message_id not in self.messages._messages:
                raise NotFoundError("Message not found")
            msg = self.messages._messages[message_id]
            if msg.author_id != editor_id:
                raise AuthorizationError("Not the author")
            if not new_body and not msg.attachments:
                raise ValidationError("Body cannot be empty when there are no attachments")
            msg.body = new_body
            msg.edited_at = self._now_dt()
            return _clone_msg(msg)

    def add_attachment(self, message_id, user_id, filename, data):
        with self._lock:
            if message_id not in self.messages._messages:
                raise NotFoundError("Message not found")
            msg = self.messages._messages[message_id]
            if msg.author_id != user_id:
                raise AuthorizationError("Not the author")
            if not filename:
                raise ValidationError("Filename must not be empty")
            att = Attachment(filename=filename, size=len(data),
                             uploaded_by=user_id, uploaded_at=self._now_dt())
            msg.attachments.append(att)
            return _clone_msg(msg)

    def list_messages_by_project(self, project_id):
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            ids = self.messages._by_project.get(project_id, [])
            msgs_dict = self.messages._messages
            return [_clone_msg(msgs_dict[i]) for i in ids if i in msgs_dict]

    def list_messages_by_task(self, task_id):
        with self._lock:
            if task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")
            ids = self.messages._by_task.get(task_id, [])
            msgs_dict = self.messages._messages
            return [_clone_msg(msgs_dict[i]) for i in ids if i in msgs_dict]

    def delete_message(self, message_id, user_id):
        with self._lock:
            if message_id not in self.messages._messages:
                raise NotFoundError("Message not found")
            msg = self.messages._messages[message_id]
            if msg.author_id != user_id:
                raise AuthorizationError("Not the author")
            del self.messages._messages[message_id]
            if msg.project_id is not None:
                lst = self.messages._by_project.get(msg.project_id, [])
                if message_id in lst:
                    lst.remove(message_id)
            if msg.task_id is not None:
                lst = self.messages._by_task.get(msg.task_id, [])
                if message_id in lst:
                    lst.remove(message_id)

    # -----------------------------------------------------------------------
    # Performance
    # -----------------------------------------------------------------------

    def get_completion_rate(self, user_id):
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            ids = self.tasks._by_assignee.get(user_id, set())
            tasks = [self.tasks._tasks[i] for i in ids if i in self.tasks._tasks]
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            ids = self.tasks._by_assignee.get(user_id, set())
            tasks_dict = self.tasks._tasks
            done = [
                t for i in ids
                if (t := tasks_dict.get(i)) is not None
                and t.status == TaskStatus.COMPLETED
                and t.started_at is not None
                and t.completed_at is not None
            ]
            if not done:
                return None
            total = sum(
                (t.completed_at - t.started_at).total_seconds() for t in done
            )
            return total / len(done)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if rater_id not in self.users._users:
                raise NotFoundError("Rater not found")
            if ratee_id not in self.users._users:
                raise NotFoundError("Ratee not found")
            if rater_id == ratee_id:
                raise ConflictError("Cannot rate yourself")
            if not (1 <= score <= 5):
                raise ValidationError("Score must be between 1 and 5")
            if task_id is not None and task_id not in self.tasks._tasks:
                raise NotFoundError("Task not found")

            rid = self._next_id()
            rating = Rating(id=rid, rater_id=rater_id, ratee_id=ratee_id,
                            score=score, feedback=feedback, task_id=task_id,
                            created_at=self._now_dt())
            self.performance._ratings[rid] = rating
            self.performance._ratings_by_ratee.setdefault(ratee_id, []).append(rid)
            return replace(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            ids = self.performance._ratings_by_ratee.get(user_id, [])
            ratings_dict = self.performance._ratings
            ratings = [replace(ratings_dict[i]) for i in ids if i in ratings_dict]
            count = len(ratings)
            avg = sum(r.score for r in ratings) / count if count > 0 else 0.0
            return {"count": count, "average": avg, "ratings": ratings}

    def get_user_dashboard(self, user_id):
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            ids = self.tasks._by_assignee.get(user_id, set())
            tasks_dict = self.tasks._tasks
            tasks = [tasks_dict[i] for i in ids if i in tasks_dict]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            rate = completed / total if total > 0 else 0.0

            done = [t for t in tasks
                    if t.status == TaskStatus.COMPLETED
                    and t.started_at is not None and t.completed_at is not None]
            avg_time = (
                sum((t.completed_at - t.started_at).total_seconds() for t in done) / len(done)
                if done else None
            )

            r_ids = self.performance._ratings_by_ratee.get(user_id, [])
            r_list = [self.performance._ratings[i] for i in r_ids
                      if i in self.performance._ratings]
            r_count = len(r_list)
            r_avg = sum(r.score for r in r_list) / r_count if r_count > 0 else 0.0

            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": rate,
                "average_completion_time": avg_time,
                "rating_count": r_count,
                "rating_average": r_avg,
            }

    # -----------------------------------------------------------------------
    # Reports
    # -----------------------------------------------------------------------

    def project_progress_report(self, project_id):
        with self._lock:
            if project_id not in self.projects._projects:
                raise NotFoundError("Project not found")
            ids = self.tasks._by_project.get(project_id, set())
            tasks_dict = self.tasks._tasks
            tasks = [tasks_dict[i] for i in ids if i in tasks_dict]
            total = len(tasks)
            now = self._now_dt()

            status_counts = {s.value: 0 for s in TaskStatus}
            for t in tasks:
                status_counts[t.status.value] += 1

            completed = status_counts[TaskStatus.COMPLETED.value]
            rate = completed / total if total > 0 else 0.0
            overdue = sum(
                1 for t in tasks
                if t.deadline is not None
                and now > t.deadline
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee = {}
            for t in tasks:
                if t.assignee_id is None:
                    continue
                if t.assignee_id not in per_assignee:
                    per_assignee[t.assignee_id] = {s.value: 0 for s in TaskStatus}
                    per_assignee[t.assignee_id]["total"] = 0
                per_assignee[t.assignee_id][t.status.value] += 1
                per_assignee[t.assignee_id]["total"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None and project_id not in self.projects._projects:
                raise NotFoundError("Project not found")

            if project_id is not None:
                ids = self.tasks._by_project.get(project_id, set())
                tasks_dict = self.tasks._tasks
                scope = [tasks_dict[i] for i in ids if i in tasks_dict]
            else:
                scope = list(self.tasks._tasks.values())

            assignee_ids = {t.assignee_id for t in scope if t.assignee_id is not None}
            rows = []
            for uid in assignee_ids:
                utasks = [t for t in scope if t.assignee_id == uid]
                total = len(utasks)
                comp = sum(1 for t in utasks if t.status == TaskStatus.COMPLETED)
                ip = sum(1 for t in utasks if t.status == TaskStatus.IN_PROGRESS)
                ns = sum(1 for t in utasks if t.status == TaskStatus.NOT_STARTED)
                rate = comp / total if total > 0 else 0.0
                done = [t for t in utasks
                        if t.status == TaskStatus.COMPLETED
                        and t.started_at is not None and t.completed_at is not None]
                avg_time = (
                    sum((t.completed_at - t.started_at).total_seconds()
                        for t in done) / len(done)
                    if done else None
                )
                rows.append({
                    "user_id": uid,
                    "total_tasks": total,
                    "completed_tasks": comp,
                    "in_progress_tasks": ip,
                    "not_started_tasks": ns,
                    "completion_rate": rate,
                    "average_completion_time": avg_time,
                })

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            if user_id not in self.users._users:
                raise NotFoundError("User not found")
            ids = self.tasks._by_assignee.get(user_id, set())
            tasks_dict = self.tasks._tasks
            tasks = [tasks_dict[i] for i in ids if i in tasks_dict]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            task_list = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                    "deadline": str(t.deadline) if t.deadline else None,
                    "started_at": str(t.started_at) if t.started_at else None,
                    "completed_at": str(t.completed_at) if t.completed_at else None,
                }
                for t in sorted(tasks, key=lambda x: x.id)
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "tasks": task_list,
            }

    def export_report(self, report, fmt):
        with self._lock:
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be a ReportFormat instance")
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if fmt == ReportFormat.CSV:
                return self._export_csv(report)
            return self._export_pdf(report)

    def _export_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")
        if rows is not None and isinstance(rows, list):
            # Union of all keys across rows preserving first-seen order
            all_keys = list(dict.fromkeys(k for row in rows for k in row))
            if not all_keys:
                all_keys = ["report"]
            writer.writerow(all_keys)
            for row in rows:
                writer.writerow([row.get(k, "") for k in all_keys])
        else:
            writer.writerow(["key", "value"])
            for k, v in report.items():
                writer.writerow(
                    [k, json.dumps(v) if isinstance(v, (dict, list)) else v]
                )
        return output.getvalue()

    def _export_pdf(self, report):
        # Render report as text lines for embedding in PDF content stream
        lines = []
        for k, v in report.items():
            raw = json.dumps(v) if isinstance(v, (dict, list)) else str(v)
            lines.append("{0}: {1}".format(k, raw))

        # Build PDF page content stream using basic text operators
        parts = ["BT", "/F1 10 Tf", "50 740 Td"]
        first = True
        for raw_line in lines[:60]:
            safe = raw_line.encode("ascii", "replace").decode("ascii")
            # Escape PDF string delimiters
            escaped = safe.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
            if len(escaped) > 200:
                escaped = escaped[:197] + "..."
            if not first:
                parts.append("0 -14 Td")
            first = False
            parts.append("({0}) Tj".format(escaped))
        parts.append("ET")

        stream = "\n".join(parts).encode("latin-1")
        slen = len(stream)

        obj1 = b"1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n"
        obj2 = b"2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n"
        obj3 = (
            b"3 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792]"
            b" /Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>\nendobj\n"
        )
        obj4 = (
            "4 0 obj\n<< /Length {0} >>\nstream\n".format(slen).encode("latin-1")
            + stream
            + b"\nendstream\nendobj\n"
        )
        obj5 = b"5 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n"

        objs = [obj1, obj2, obj3, obj4, obj5]
        header = b"%PDF-1.4\n"
        offsets = []
        body = b""
        for obj in objs:
            offsets.append(len(header) + len(body))
            body += obj

        xref_offset = len(header) + len(body)
        n = len(objs) + 1  # +1 for the null object (entry 0)
        xref = "xref\n0 {0}\n".format(n).encode("latin-1")
        xref += b"0000000000 65535 f \n"
        for off in offsets:
            xref += "{0:010d} 00000 n \n".format(off).encode("latin-1")

        trailer = (
            "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF\n"
            .format(n, xref_offset)
            .encode("latin-1")
        )
        return header + body + xref + trailer
